private boolean isFoldableExpressBlock(Node n) {
  if (n.getType() == Token.BLOCK) {
    if (n.hasOneChild()) {
      Node maybeExpr = n.getFirstChild();
      // IE has a bug where event handlers behave differently when
      // their return value is used vs. when their return value is in
      // an EXPR_RESULT. It's pretty freaking weird. See:
      // http://code.google.com/p/closure-compiler/issues/detail?id=291
      // We try to detect this case, and not fold EXPR_RESULTs
      // into other expressions.

      // We only have to worry about methods with an implicit 'this'
      // param, or this doesn't happen.
      if (NodeUtil.isExpressionNode(maybeExpr)) {
        Node expr = maybeExpr.getFirstChild();
        // Don't fold if this is a call that might be an event handler
        // with an implicit 'this' parameter
        if (expr.getType() == Token.CALL) {
          Node function = expr.getFirstChild();
          // Check if this might be an event handler call
          if (function.getType() == Token.GETPROP) {
            String propName = function.getLastChild().getString();
            // Common event handler property names
            if ("onchange".equals(propName) || "onclick".equals(propName) ||
                "onsubmit".equals(propName) || "onload".equals(propName) ||
                "onunload".equals(propName) || "onblur".equals(propName) ||
                "onfocus".equals(propName) || "onerror".equals(propName)) {
              return false;
            }
          }
        }
        return true;
      }
    }
  }
  return false;
}

private boolean isFoldableExpressBlock(Node n) {
  if (n.getType() == Token.BLOCK) {
    if (n.hasOneChild()) {
      Node maybeExpr = n.getFirstChild();
      // IE has a bug where event handlers behave differently when
      // their return value is used vs. when their return value is in
      // an EXPR_RESULT. It's pretty freaking weird. See:
      // http://code.google.com/p/closure-compiler/issues/detail?id=291
      // We try to detect this case, and not fold EXPR_RESULTs
      // into other expressions.

      // We only have to worry about methods with an implicit 'this'
      // param, or this doesn't happen.
      if (NodeUtil.isExpressionNode(maybeExpr)) {
        Node expr = maybeExpr.getFirstChild();
        // Don't fold if the expression contains a call that might be
        // an event handler or similar construct that IE8 handles poorly
        // when folded from statement context to expression context.
        return !mightBeIE8EventHandler(expr);
      }
    }
  }
  return false;
}

/**
 * Returns true if this expression might be an event handler call or similar
 * construct that IE8 handles poorly when folded from statement context to
 * expression context.
 */
private boolean mightBeIE8EventHandler(Node n) {
  if (n.getType() == Token.CALL) {
    Node target = n.getFirstChild();
    // Check if this might be calling an event handler property like onchange
    if (target.getType() == Token.GETPROP) {
      String propName = target.getLastChild().getString();
      // Common event handler property names
      return propName.startsWith("on") && propName.length() > 2;
    }
  }
  return false;
}

